(N'QUERY_WAIT_ERRHDL_SERVICE',N'OTHER_OR_NEW',2,0,N'Identified for informational purposes only. Not supported. Future compatibility is not guaranteed.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'RECOVER_CHANGEDB',N'OTHER_OR_NEW',2,0,N'Occurs during synchronization of database status in warm standby database.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'REPLICA_WRITES',N'OTHER_OR_NEW',2,0,N'Occurs while a task waits for completion of page writes to database snapshots or DBCC replicas.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'REPL_CACHE_ACCESS',N'REPLICATION',2,0,N'Occurs during synchronization on a replication article cache. During these waits, the replication log reader stalls, and data definition language (DDL) statements on a published table are blocked.',N'SQL Server Replication und Distribution.',N'Hohe aktive Werte können Log Reader, Distribution oder DDL blockieren.',N'Agenthistorie, Distribution-Datenbank, Latenz und Fehler prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'REPL_SCHEMA_ACCESS',N'REPLICATION',2,0,N'Occurs during synchronization of replication schema version information. This state exists when DDL statements are executed on the replicated object, and when the log reader builds or consumes versioned schema based on DDL occurrence.',N'SQL Server Replication und Distribution.',N'Hohe aktive Werte können Log Reader, Distribution oder DDL blockieren.',N'Agenthistorie, Distribution-Datenbank, Latenz und Fehler prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'REQUEST_DISPENSER_PAUSE',N'OTHER_OR_NEW',2,0,N'Occurs when a task is waiting for all outstanding I/O to complete, so that I/O to a file can be frozen for snapshot backup.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'REQUEST_FOR_DEADLOCK_SEARCH',N'BENIGN_BACKGROUND',0,1,N'Deadlock Monitor wartet bis zum nächsten Suchintervall.',N'Normaler SQL-Server-Hintergrundtask.',N'Hohe kumulative Werte sind erwartbar.',N'Nicht als Deadlock-Indikator verwenden; Deadlock Events separat prüfen.',N'FRAMEWORK_CURATED',N'CURATED'),
(N'RESERVED_MEMORY_ALLOCATION_EXT',N'MEMORY',2,0,N'This wait type is when a thread is switching to preemptive mode while allocating memory that has previously been reserved for the query (i.e. the query execution memory grant). The preemptive switch is so that the code being executed does not have to check for quantum exhaustion.',N'Speicherzuteilung, Memory Grants oder interne Memory-Manager.',N'Hohe Werte verzögern Start oder Ausführung von Abfragen.',N'Pending Grants, Grantgrößen, Cardinality, Spills und max server memory prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'RESMGR_THROTTLED',N'OTHER_OR_NEW',2,0,N'Occurs when a new request comes in and is throttled based on the GROUP_MAX_REQUESTS setting.',N'Spezialisierter, interner oder neuer SQL-Server-Wait-Type.',N'Hohe Werte sind nur im Delta- und Workload-Kontext bewertbar.',N'Aktive Tasks, Ressource, Version, SQLskills-Detailseite und Herstellerdokumentation prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'RESOURCE_QUEUE',N'BENIGN_BACKGROUND',0,1,N'Dies ist der normale Leerlaufzustand für im Hintergrund ausgeführte Threads in SQL Server. - (Occurs during synchronization of various internal resource queues.)',N'Normaler Idle-, Timer-, Queue- oder Hintergrundzustand.',N'Hohe kumulative Werte sind in der Regel erwartbar und kein Engpassbeweis.',N'Standardmäßig aus Top-Ranking ausblenden; nur bei passender Funktionsstörung untersuchen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'RESOURCE_SEMAPHORE',N'MEMORY',4,0,N'Warten auf einen Query Execution Memory Grant.',N'Große oder viele konkurrierende Sort-/Hash-Operationen und Überschätzungen.',N'Queries starten verspätet; Durchsatz sinkt.',N'Memory Grants, Pending Grants, Cardinality, Spills und max server memory prüfen.',N'FRAMEWORK_CURATED',N'CURATED'),
(N'RESOURCE_SEMAPHORE_MUTEX',N'MEMORY',2,0,N'Occurs while a query waits for its request for a thread reservation to be fulfilled. It also occurs when synchronizing query compile and memory grant requests.',N'Speicherzuteilung, Memory Grants oder interne Memory-Manager.',N'Hohe Werte verzögern Start oder Ausführung von Abfragen.',N'Pending Grants, Grantgrößen, Cardinality, Spills und max server memory prüfen.',N'REFERENCE_NORMALIZED',N'IMPORTED_REVIEW_REQUIRED'),
(N'RESOURCE_SEMAPHORE_QUERY_COMPILE',N'MEMORY',4,0,N'Warten auf Speicher für die Plankompilierung.',N'Viele komplexe Kompilierungen oder Compile-Memory-Druck.',N'Kompilierungen verzögern neue Requests.',N'Compile Rate, Ad-hoc-Pläne, Plan Cache und komplexe Statements prüfen.',N'FRAMEWORK_CURATED',N'CURATED');

UPDATE [c] SET [WaitGroup]=[s].[WaitGroup],[Severity]=[s].[Severity],[IsGenerallyBenign]=[s].[IsGenerallyBenign],[Meaning]=[s].[Meaning],
 [TypicalOccurrence]=[s].[TypicalOccurrence],[HighWaitImpact]=[s].[HighWaitImpact],[RecommendedChecks]=[s].[RecommendedChecks],
 [HelpUrl]=N'https://www.sqlskills.com/help/waits/'+[s].[WaitType],[DescriptionSource]=[s].[DescriptionSource],
 [DescriptionQuality]=[s].[DescriptionQuality],[SourceReference]=N'normalized reference corpus',
 [IsFrameworkDefault]=1,[LastUpdatedUtc]=SYSUTCDATETIME()
FROM [monitor].[WaitTypeCatalog] [c] JOIN @Seed [s] ON [s].[WaitType]=[c].[WaitType] WHERE [c].[IsFrameworkDefault]=1;

INSERT [monitor].[WaitTypeCatalog]
([WaitType],[WaitGroup],[Severity],[IsGenerallyBenign],[Meaning],[TypicalOccurrence],[HighWaitImpact],[RecommendedChecks],[HelpUrl],
 [DescriptionSource],[DescriptionQuality],[SourceReference],[IsFrameworkDefault])
SELECT [s].[WaitType],[s].[WaitGroup],[s].[Severity],[s].[IsGenerallyBenign],[s].[Meaning],[s].[TypicalOccurrence],[s].[HighWaitImpact],[s].[RecommendedChecks],
 N'https://www.sqlskills.com/help/waits/'+[s].[WaitType],[s].[DescriptionSource],[s].[DescriptionQuality],
 N'normalized reference corpus',1
FROM @Seed [s] WHERE NOT EXISTS(SELECT 1 FROM [monitor].[WaitTypeCatalog] [c] WHERE [c].[WaitType]=[s].[WaitType]);
GO
